/**
 * @summary Get available time slots for a lawyer
 */
export const getGetLawyerAvailabilityUrl = (
  lawyerId: number,
  params?: GetLawyerAvailabilityParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/lawyers/${lawyerId}/availability?${stringifiedParams}`
    : `/api/lawyers/${lawyerId}/availability`;
};

